public inline fun isLeft(predicate: (A) -> Boolean): Boolean {
  contract {
    returns(true) implies (this@Either is Left)
    callsInPlace(predicate, InvocationKind.AT_MOST_ONCE)
    (this@Either is Left) holdsIn predicate
  }
  return this@Either is Left<A> && predicate(value)
}

@IgnorableReturnValue
  public inline fun onRight(action: (right: B) -> Unit): Either<A, B> {
    contract {
      callsInPlace(action, InvocationKind.AT_MOST_ONCE)
      (this@Either is Right) holdsIn action
    }
    return also { if (it.isRight()) action(it.value) }
  }

public inline fun onLeft(action: (left: A) -> Unit): Either<A, B> {
  contract {
    callsInPlace(action, InvocationKind.AT_MOST_ONCE)
    (this@Either is Left) holdsIn action
  }
  return also { if (it.isLeft()) action(it.value) }
}

public fun getOrNull(): B? {
  contract {
    returnsNotNull() implies (this@Either is Right)
  }
  return getOrElse { null }
}

public inline fun onNone(action: () -> Unit): Option<A>  {
  contract {
    callsInPlace(action, InvocationKind.AT_MOST_ONCE)
    (this@Option is None) holdsIn action
  }
  return also { if (it.isNone()) action() }
}

public inline fun isSome(predicate: (A) -> Boolean): Boolean {
  contract {
    callsInPlace(predicate, InvocationKind.AT_MOST_ONCE)
    returns(true) implies (this@Option is Some)
    (this@Option is Some) holdsIn predicate
  }
  return this@Option is Some<A> && predicate(value)
}

