inline fun <reified T : Any> createScope(scopeId: ScopeID, source: Any? = null, scopeArchetype : TypeQualifier? = null): Scope {
    val qualifier = TypeQualifier(T::class)
    return scopeRegistry.createScope(scopeId, qualifier, source, scopeArchetype)
}

private fun <T> resolveFromRegistry(
    scope: Scope,
    ctx: ResolutionContext
): T? {
    return resolveDirectDefinition(scope, ctx)
        ?: resolveFromScopeSource(scope, ctx)
        ?: resolveFromLinkedScopes(scope, ctx)
}

private fun CoroutineScope(logger: Logger?): CoroutineScope {
    val context = SupervisorJob() +
        CoroutineExceptionHandler { _, throwable -> logger?.log(TAG, throwable) }
    return CoroutineScope(context)
}

override fun shutdown() {
    if (shutdown.getAndSet(true)) return
    scope.cancel()
    systemCallbacks.shutdown()
    memoryCache?.clear()
}

fun getOrCreateScope(scopeId: ScopeID, qualifier: Qualifier, source: Any? = null): Scope {
    return scopeRegistry.getScopeOrNull(scopeId) ?: createScope(scopeId, qualifier, source)
}

inline fun hasType(clazz: KClass<*>): Boolean {
    return primaryType == clazz || secondaryTypes.contains(clazz)
}

inline fun `is`(clazz: KClass<*>, qualifier: Qualifier?, scopeDefinition: Qualifier): Boolean {
    return hasType(clazz) && this.qualifier == qualifier && this.scopeQualifier == scopeDefinition
}

infix fun <S : Any> KoinDefinition<out S>.bind(clazz: KClass<S>): KoinDefinition<out S> {
    val def = factory.beanDefinition
    def.addSecondaryType(clazz)
    val mapping = indexKey(clazz, def.qualifier, def.scopeQualifier)
    module.saveMapping(mapping, factory)
    return this
}

fun <T> KoinDefinition<T>.override(): KoinDefinition<T> {
    factory.beanDefinition.allowOverride = true
    return this
}

fun getScope(scopeId: ScopeID): Scope {
    return scopeRegistry.getScopeOrNull(scopeId)
        ?: throw ScopeNotCreatedException("No scope found for id '$scopeId'")
}

fun withDistinctOn(vararg columns: Column<*>): T = apply {
        if (columns.isEmpty()) return@apply

        require(!distinct) { "DISTINCT ON cannot be used with the DISTINCT modifier. Only one of them should be applied." }
        distinctOn = (distinctOn ?: emptyList()) + columns
    } as T

fun <T : Any> wrapAsExpression(query: AbstractQuery<*>) = object : Expression<T?>() {
    override fun toQueryBuilder(queryBuilder: QueryBuilder) = queryBuilder {
        append("(")
        query.prepareSQL(this)
        append(")")
    }
}

private class SupervisorJobImpl(parent: Job?) : JobImpl(parent) {
    override fun childCancelled(cause: Throwable): Boolean = false
}

private class SupervisorCoroutine<in T>(
    context: CoroutineContext,
    uCont: Continuation<T>
) : ScopeCoroutine<T>(context, uCont) {
    override fun childCancelled(cause: Throwable): Boolean = false
}

public suspend inline operator fun <T> CoroutineDispatcher.invoke(
    noinline block: suspend CoroutineScope.() -> T
): T = withContext(this, block)

internal fun SerialDescriptor.carrierDescriptor(module: SerializersModule): SerialDescriptor = when {
    kind == SerialKind.CONTEXTUAL -> module.getContextualDescriptor(this)?.carrierDescriptor(module) ?: this
    isInline -> getElementDescriptor(0).carrierDescriptor(module)
    else     -> this
}

data class ConstantMatcher<in T : Any>(
    val constValue: Boolean,
) : Matcher<T> {
    override fun match(arg: T?): Boolean = constValue

    override fun toString(): String = if (constValue) "any()" else "none()"
}

data class ThrowingAnswer(
    val ex: Throwable,
) : Answer<Nothing> {
    override fun answer(call: Call): Nothing = throw ex
}

fun CompositeMatcher<*>.captureSubMatchers(arg: Any?) {
    subMatchers?.let {
        it
            .filterIsInstance<CapturingMatcher>()
            .forEach { matcher -> matcher.capture(arg) }
    }
}

internal inline fun Buffer.commonWriteByte(b: Int): Buffer {
  val tail = writableSegment(1)
  tail.data[tail.limit++] = b.toByte()
  size += 1L
  return this
}

